  // --- Бележки ---
  notes_title: { bg:'📝 Бележки', ru:'📝 Заметки', uk:'📝 Нотатки', en:'📝 Notes', de:'📝 Notizen', fr:'📝 Notes', es:'📝 Notas', 'es-MX':'📝 Notas', it:'📝 Note', pt:'📝 Notas', ar:'📝 الملاحظات', hi:'📝 नोट्स', ja:'📝 メモ', ky:'📝 Эскертүүлөр', 'zh-Hant':'📝 筆記' },
  notes_intro: { bg:'Запиши бележки, които роботът да помни — и да ти ги ИЗГОВАРЯ на избрания език (един от 15-те на екосистемата).', ru:'Записывайте заметки, которые робот запомнит — и будет ПРОИЗНОСИТЬ их на выбранном языке (одном из 15 в экосистеме).', uk:'Записуйте нотатки, які робот запам’ятає — і ОЗВУЧУВАТИМЕ їх обраною мовою (однією з 15 в екосистемі).', en:'Write notes the robot will remember — and SPEAK them aloud in the language you choose (one of the 15 in the ecosystem).', de:'Schreibe Notizen, die der Roboter sich merkt — und sie in der gewählten Sprache VORLIEST (eine der 15 im Ökosystem).', fr:'Écris des notes que le robot retiendra — et qu’il LIRA à voix haute dans la langue choisie (l’une des 15 de l’écosystème).', es:'Escribe notas que el robot recordará — y las DIRÁ en voz alta en el idioma que elijas (uno de los 15 del ecosistema).', 'es-MX':'Escribe notas que el robot recordará — y las DIRÁ en voz alta en el idioma que elijas (uno de los 15 del ecosistema).', it:'Scrivi note che il robot ricorderà — e le LEGGERÀ ad alta voce nella lingua scelta (una delle 15 dell’ecosistema).', pt:'Escreva notas que o robô vai lembrar — e FALAR em voz alta no idioma escolhido (um dos 15 do ecossistema).', ar:'اكتب ملاحظات يتذكّرها الروبوت — وينطقها بصوت عالٍ باللغة التي تختارها (إحدى الـ15 في المنظومة).', hi:'ऐसे नोट्स लिखें जो रोबोट याद रखे — और चुनी हुई भाषा (इकोसिस्टम की 15 में से) में बोलकर सुनाए।', ja:'ロボットが覚えるメモを書くと、選んだ言語（エコシステムの15言語のいずれか）で読み上げます。', ky:'Робот эстеп кала турган эскертүүлөрдү жазыңыз — жана аларды тандалган тилде (экосистеманын 15 тилинин бири) АЙТЫП берет.', 'zh-Hant':'寫下機器人會記住的筆記 — 並以你選的語言（生態系 15 種之一）朗讀出來。' },
  notes_new: { bg:'Нова бележка', ru:'Новая заметка', uk:'Нова нотатка', en:'New note', de:'Neue Notiz', fr:'Nouvelle note', es:'Nueva nota', 'es-MX':'Nueva nota', it:'Nuova nota', pt:'Nova nota', ar:'ملاحظة جديدة', hi:'नया नोट', ja:'新しいメモ', ky:'Жаңы эскертүү', 'zh-Hant':'新增筆記' },
  notes_text_ph: { bg:'напр. Купи хляб и мляко; обади се на мама в 18:00', ru:'напр. Купить хлеб и молоко; позвонить маме в 18:00', uk:'напр. Купити хліб і молоко; подзвонити мамі о 18:00', en:'e.g. Buy bread and milk; call mom at 18:00', de:'z. B. Brot und Milch kaufen; Mama um 18:00 anrufen', fr:'ex. Acheter du pain et du lait ; appeler maman à 18h00', es:'p. ej. Comprar pan y leche; llamar a mamá a las 18:00', 'es-MX':'p. ej. Comprar pan y leche; llamar a mamá a las 18:00', it:'es. Comprare pane e latte; chiamare mamma alle 18:00', pt:'ex. Comprar pão e leite; ligar para a mãe às 18:00', ar:'مثال: اشترِ خبزًا وحليبًا؛ اتصل بأمي الساعة 18:00', hi:'जैसे ब्रेड और दूध खरीदें; 18:00 बजे माँ को कॉल करें', ja:'例: パンと牛乳を買う；18時にお母さんに電話', ky:'мис. Нан жана сүт сатып ал; 18:00дө апама чал', 'zh-Hant':'例如 買麵包和牛奶；18:00 打給媽媽' },
  notes_speak_lang: { bg:'Език за изговаряне', ru:'Язык произношения', uk:'Мова озвучення', en:'Speaking language', de:'Sprechsprache', fr:'Langue de lecture', es:'Idioma de voz', 'es-MX':'Idioma de voz', it:'Lingua di lettura', pt:'Idioma de fala', ar:'لغة النطق', hi:'बोलने की भाषा', ja:'読み上げ言語', ky:'Айтуу тили', 'zh-Hant':'朗讀語言' },
